export const AipanPattern = ({ className = "", color = "#C4522A", opacity = 0.12 }: { className?: string; color?: string; opacity?: number }) => (
  <svg className={className} viewBox="0 0 200 200" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <g fill="none" stroke={color} strokeWidth="1" opacity={opacity}>
      {/* Outer petals */}
      <circle cx="100" cy="100" r="80" />
      <circle cx="100" cy="100" r="60" />
      <circle cx="100" cy="100" r="40" />
      <circle cx="100" cy="100" r="20" />
      <circle cx="100" cy="100" r="8" fill={color} fillOpacity={opacity} />
      {/* Cross lines */}
      <line x1="20" y1="100" x2="180" y2="100" />
      <line x1="100" y1="20" x2="100" y2="180" />
      {/* Diagonal lines */}
      <line x1="43" y1="43" x2="157" y2="157" />
      <line x1="157" y1="43" x2="43" y2="157" />
      {/* Lotus petals */}
      <path d="M100,20 Q120,60 100,80 Q80,60 100,20" />
      <path d="M100,180 Q120,140 100,120 Q80,140 100,180" />
      <path d="M20,100 Q60,120 80,100 Q60,80 20,100" />
      <path d="M180,100 Q140,120 120,100 Q140,80 180,100" />
      {/* Diagonal petals */}
      <path d="M43,43 Q75,75 67,90 Q52,68 43,43" />
      <path d="M157,43 Q125,75 133,90 Q148,68 157,43" />
      <path d="M43,157 Q75,125 67,110 Q52,132 43,157" />
      <path d="M157,157 Q125,125 133,110 Q148,132 157,157" />
      {/* Inner dots */}
      <circle cx="100" cy="48" r="3" fill={color} fillOpacity={opacity * 2} stroke="none" />
      <circle cx="100" cy="152" r="3" fill={color} fillOpacity={opacity * 2} stroke="none" />
      <circle cx="48" cy="100" r="3" fill={color} fillOpacity={opacity * 2} stroke="none" />
      <circle cx="152" cy="100" r="3" fill={color} fillOpacity={opacity * 2} stroke="none" />
      <circle cx="65" cy="65" r="2" fill={color} fillOpacity={opacity * 2} stroke="none" />
      <circle cx="135" cy="65" r="2" fill={color} fillOpacity={opacity * 2} stroke="none" />
      <circle cx="65" cy="135" r="2" fill={color} fillOpacity={opacity * 2} stroke="none" />
      <circle cx="135" cy="135" r="2" fill={color} fillOpacity={opacity * 2} stroke="none" />
    </g>
  </svg>
);

export const AipanBorderPattern = () => (
  <svg viewBox="0 0 400 40" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="none" aria-hidden="true">
    <g fill="none" stroke="#C4522A" strokeWidth="0.8" opacity="0.3">
      {[0, 40, 80, 120, 160, 200, 240, 280, 320, 360].map((x) => (
        <g key={x} transform={`translate(${x + 20}, 20)`}>
          <circle cx="0" cy="0" r="10" />
          <circle cx="0" cy="0" r="6" />
          <circle cx="0" cy="0" r="2" fill="#C4522A" fillOpacity="0.3" stroke="none" />
          <line x1="-10" y1="0" x2="10" y2="0" />
          <line x1="0" y1="-10" x2="0" y2="10" />
          <line x1="-7" y1="-7" x2="7" y2="7" />
          <line x1="7" y1="-7" x2="-7" y2="7" />
        </g>
      ))}
    </g>
  </svg>
);
